===== pruneLabels.ts =====
/**
 * prune-labels mode: enumerate the current workspace members at the pushed ref and
 * delete any `<prefix>/*` repository label whose member no longer exists, keeping
 * the label set in lockstep with the workspace.
 */
import { collectMembers } from "./collectMembers.ts";
import type { GitHubApi } from "./githubApi.ts";

/** Inputs for prune mode, resolved from the push event + inputs. */
export interface PruneInput {
  ref: string;
  prefix: string;
}

/** Deleted orphan labels, for the step summary. */
export interface PruneResult {
  deleted: string[];
}

export async function pruneLabels(api: GitHubApi, input: PruneInput): Promise<PruneResult> {
  const members = await collectMembers(api, input.ref, input.prefix);
  const live = new Set(members.map((member) => member.label));

  const existing = (await api.listRepoLabels()).filter((label) => label.startsWith(input.prefix));
  const orphans = existing.filter((label) => !live.has(label)).sort();

  for (const label of orphans) {
    await api.deleteLabel(label);
  }
  return { deleted: orphans };
}

===== reconcileLabels (what it prunes) =====
/**
 * Pure set-reconciliation for a PR's workspace labels. Given the labels currently
 * on the PR (already filtered to our prefix) and the labels the diff should carry,
 * it returns which to add and which to remove — no I/O, so it is trivially tested.
 *
 * @example
 *   reconcileLabels(["a/old", "a/x"], ["a/x", "a/new"]);
 *   // { add: ["a/new"], remove: ["a/old"] }
 */

/** The add/remove delta to apply to a pull request's labels. */
export interface LabelReconciliation {
  add: string[];
  remove: string[];
}

/**
 * Computes the add/remove delta between the current and desired label sets.
 * Order-independent; both lists are de-duplicated and sorted for stable output.
 */
export function reconcileLabels(current: string[], desired: string[]): LabelReconciliation {
  const currentSet = new Set(current);
  const desiredSet = new Set(desired);
  return {
    add: dedupeSorted(desired.filter((label) => !currentSet.has(label))),
    remove: dedupeSorted(current.filter((label) => !desiredSet.has(label))),
  };
}

function dedupeSorted(values: string[]): string[] {
  return [...new Set(values)].sort();
}
